function autoFormatTime(x){let r=x['value']['replace'](/\D/g,'');switch(r['length']>0x4&&(r=r['slice'](0x0,0x4)),r['length']){case 0x0:case 0x1:case 0x2:x['value']=r;break;case 0x3:if(parseInt(r['slice'](0x0,0x2),0xa)<=0x17)x['value']=r['slice'](0x0,0x2)+':'+r['slice'](0x2);else{let F=r['slice'](0x0,0x1)['padStart'](0x2,'0'),P=r['slice'](0x1);x['value']=F+':'+P;}break;case 0x4:let f=r['slice'](0x0,0x2),d=r['slice'](0x2);x['value']=f+':'+d;}}function transformTimeValue(x){let r=x['trim']();if(/^\d{2}$/['test'](r))return r[0x0]['padStart'](0x2,'0')+':'+r[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](r))return 0x3===r['length']?parseInt(r['slice'](0x0,0x2),0xa)<=0x17?r['slice'](0x0,0x2)+':'+r['slice'](0x2):r['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+r['slice'](0x1):r['slice'](0x0,0x2)+':'+r['slice'](0x2);if(r['includes'](':')){let [f,d]=r['split'](':');return d||(d='00'),f=f['padStart'](0x2,'0'),d=d['padStart'](0x2,'0'),f+':'+d;}return r;}